# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
import uuid
from collections import defaultdict
from typing import Dict, Set, List, Optional
from dataclasses import dataclass, asdict

@dataclass
class Item:
    id: str
    name: str
    type: str
    value: int
    owner_id: str

@dataclass
class Player:
    id: str
    username: str
    inventory: Dict[str, int]  # item_id -> quantity

class InventorySystem:
    def __init__(self):
        self.items: Dict[str, Item] = {}
        self.players: Dict[str, Player] = {}
        self.trade_requests: Dict[str, Dict] = {}
        self.locks: Dict[str, asyncio.Lock] = defaultdict(asyncio.Lock)
    
    async def create_player(self, player_id: str, username: str):
        self.players[player_id] = Player(player_id, username, {})
    
    async def add_item_to_player(self, player_id: str, item: Item):
        if player_id not in self.players:
            return False
        
        if item.id not in self.items:
            self.items[item.id] = item
        
        if item.id not in self.players[player_id].inventory:
            self.players[player_id].inventory[item.id] = 0
        
        self.players[player_id].inventory[item.id] += 1
        return True
    
    async def remove_item_from_player(self, player_id: str, item_id: str, quantity: int = 1):
        if player_id not in self.players or item_id not in self.players[player_id].inventory:
            return False
        
        if self.players[player_id].inventory[item_id] < quantity:
            return False
        
        self.players[player_id].inventory[item_id] -= quantity
        if self.players[player_id].inventory[item_id] == 0:
            del self.players[player_id].inventory[item_id]
        
        return True
    
    async def get_player_items(self, player_id: str) -> Dict[str, int]:
        return self.players.get(player_id, Player("", "", {})).inventory.copy()
    
    async def initiate_trade(self, player1_id: str, player2_id: str, 
                           item1_id: str, item2_id: str, 
                           quantity1: int = 1, quantity2: int = 1):
        trade_id = str(uuid.uuid4())
        self.trade_requests[trade_id] = {
            'id': trade_id,
            'player1': player1_id,
            'player2': player2_id,
            'item1': item1_id,
            'item2': item2_id,
            'quantity1': quantity1,
            'quantity2': quantity2,
            'status': 'pending'
        }
        return trade_id
    
    async def accept_trade(self, trade_id: str):
        if trade_id not in self.trade_requests:
            return False
        
        trade = self.trade_requests[trade_id]
        if trade['status'] != 'pending':
            return False
        
        player1_id = trade['player1']
        player2_id = trade['player2']
        item1_id = trade['item1']
        item2_id = trade['item2']
        quantity1 = trade['quantity1']
        quantity2 = trade['quantity2']
        
        # Check if players have required items
        if (player1_id not in self.players or 
            player2_id not in self.players or 
            item1_id not in self.players[player1_id].inventory or 
            item2_id not in self.players[player2_id].inventory or
            self.players[player1_id].inventory[item1_id] < quantity1 or
            self.players[player2_id].inventory[item2_id] < quantity2):
            return False
        
        # Perform trade with locks to prevent race conditions
        async with self.locks[player1_id], self.locks[player2_id]:
            # Remove items from original owners
            await self.remove_item_from_player(player1_id, item1_id, quantity1)
            await self.remove_item_from_player(player2_id, item2_id, quantity2)
            
            # Add items to new owners
            item1 = self.items[item1_id]
            item2 = self.items[item2_id]
            
            await self.add_item_to_player(player2_id, item1)
            await self.add_item_to_player(player1_id, item2)
        
        trade['status'] = 'completed'
        return True
    
    async def cancel_trade(self, trade_id: str):
        if trade_id in self.trade_requests:
            del self.trade_requests[trade_id]
            return True
        return False

class GameServer:
    def __init__(self):
        self.inventory_system = InventorySystem()
        self.connected_players: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.player_ws_map: Dict[websockets.WebSocketServerProtocol, str] = {}
    
    async def register_player(self, websocket, player_id: str, username: str):
        self.connected_players[player_id] = websocket
        self.player_ws_map[websocket] = player_id
        await self.inventory_system.create_player(player_id, username)
        await websocket.send(json.dumps({
            "type": "player_registered",
            "player_id": player_id,
            "username": username
        }))
    
    async def handle_message(self, websocket, message: str):
        try:
            data = json.loads(message)
            msg_type = data.get("type")
            
            if msg_type == "get_inventory":
                player_id = self.player_ws_map.get(websocket)
                if player_id:
                    inventory = await self.inventory_system.get_player_items(player_id)
                    await websocket.send(json.dumps({
                        "type": "inventory_response",
                        "inventory": inventory
                    }))
            
            elif msg_type == "trade_initiate":
                player_id = self.player_ws_map.get(websocket)
                if player_id:
                    trade_id = await self.inventory_system.initiate_trade(
                        player_id,
                        data["target_player_id"],
                        data["item1_id"],
                        data["item2_id"],
                        data.get("quantity1", 1),
                        data.get("quantity2", 1)
                    )
                    await websocket.send(json.dumps({
                        "type": "trade_initiated",
                        "trade_id": trade_id
                    }))
            
            elif msg_type == "trade_accept":
                trade_id = data["trade_id"]
                success = await self.inventory_system.accept_trade(trade_id)
                await websocket.send(json.dumps({
                    "type": "trade_result",
                    "success": success,
                    "trade_id": trade_id
                }))
            
            elif msg_type == "trade_cancel":
                trade_id = data["trade_id"]
                await self.inventory_system.cancel_trade(trade_id)
                await websocket.send(json.dumps({
                    "type": "trade_cancelled",
                    "trade_id": trade_id
                }))
            
            elif msg_type == "add_item":
                player_id = self.player_ws_map.get(websocket)
                if player_id:
                    item = Item(
                        id=data["item_id"],
                        name=data["name"],
                        type=data["type"],
                        value=data["value"],
                        owner_id=player_id
                    )
                    await self.inventory_system.add_item_to_player(player_id, item)
                    await websocket.send(json.dumps({
                        "type": "item_added",
                        "item_id": item.id
                    }))
            
            elif msg_type == "remove_item":
                player_id = self.player_ws_map.get(websocket)
                if player_id:
                    success = await self.inventory_system.remove_item_from_player(
                        player_id, 
                        data["item_id"],
                        data.get("quantity", 1)
                    )
                    await websocket.send(json.dumps({
                        "type": "item_removed",
                        "success": success
                    }))
            
        except Exception as e:
            print(f"Error handling message: {e}")
            await websocket.send(json.dumps({
                "type": "error",
                "message": "An error occurred processing your request"
            }))
    
    async def handle_client(self, websocket, path):
        try:
            async for message in websocket:
                await self.handle_message(websocket, message)
        except websockets.exceptions.ConnectionClosed:
            pass
        finally:
            # Clean up on disconnect
            player_id = self.player_ws_map.get(websocket)
            if player_id:
                del self.connected_players[player_id]
                del self.player_ws_map[websocket]

# Start the server
async def main():
    server = GameServer()
    start_server = websockets.serve(server.handle_client, "localhost", 8765)
    await start_server
    print("Game server started on ws://localhost:8765")
    await asyncio.Future()  # run forever

if __name__ == "__main__":
    asyncio.run(main())